var customers = [];
var sites = [];
var compliance = {};
var survey = {};
var selectedSite = null;
var items = [];
function fmt(d) {
  if (!d) return '—';
  var dt = new Date(d);
  if (isNaN(dt)) return d;
  return dt.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function expiryClass(d) {
  if (!d) return '';
  var diff = (new Date(d) - new Date()) / (1000 * 60 * 60 * 24);
  if (diff < 0) return 'danger';
  if (diff < 90) return 'warn';
  return 'ok';
}
function escHtml(str) {
  return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
function populateCustomers(list) {
  var sel = document.getElementById('f_customer');
  if (!sel) return;
  var current = sel.value;
  sel.innerHTML = '<option value="">Select customer...</option>' + list.map(function (c) {
    return '<option value="' + c.value + '"' + (c.value == current ? ' selected' : '') + '>' + escHtml(c.label) + '</option>';
  }).join('');
}
function renderSites(list) {
  var hint = document.getElementById('site_hint');
  var tbl = document.getElementById('site_table');
  var tbody = document.getElementById('site_body');
  if (!list || !list.length) {
    if (hint) {
      hint.textContent = 'No sites found';
      hint.style.display = 'block';
    }
    if (tbl) tbl.style.display = 'none';
    return;
  }
  if (hint) hint.style.display = 'none';
  if (tbl) tbl.style.display = 'table';
  tbody.innerHTML = list.map(function (s, i) {
    var addr = [s.address1, s.address2].filter(Boolean).join(', ');
    return '<tr onclick="window.selectSite(' + i + ')" id="site_row_' + i + '"><td>' + (s.postcode || '—') + '</td><td>' + (addr || '—') + '</td><td>' + (s.city || '—') + '</td></tr>';
  }).join('');
}
function updateCompliance(c) {
  if (!c) return;
  var dial = document.getElementById('c_dial');
  var exp = document.getElementById('c_expiry');
  var msa = document.getElementById('c_msa');
  var alrt = document.getElementById('c_alert');
  if (dial) dial.textContent = c.dial_ref || '—';
  if (exp) {
    exp.textContent = fmt(c.dial_expiry);
    exp.className = 'compliance-value ' + expiryClass(c.dial_expiry);
  }
  if (msa) {
    msa.textContent = c.msa_signed || '—';
    msa.className = 'compliance-value ' + (c.msa_signed === 'Yes' ? 'ok' : c.msa_signed === 'Pending' ? 'warn' : 'danger');
  }
  if (alrt) alrt.className = 'compliance-alert' + (c.msa_signed !== 'Yes' ? ' show' : '');
}
function renderSurvey(s) {
  var card = document.getElementById('survey_card');
  if (!card) return;
  if (!s || !s.survey_id) {
    card.style.display = 'block';
    card.innerHTML = '<div class="card-header"><i class="ti ti-clipboard-check" style="font-size:13px"></i><span class="card-title">Site Survey</span></div>' + '<div class="card-body">' + '<div class="survey-alert danger-alert" style="margin-bottom:10px"><i class="ti ti-alert-triangle" style="font-size:13px;margin-right:6px"></i>No site survey on record — complete before collection</div>' + '<button onclick="window.goToSurvey()" style="font-size:12px;font-weight:600;padding:7px 14px;border-radius:6px;border:none;cursor:pointer;background:#05042E;color:#A3E851;font-family:Figtree,sans-serif;width:100%">Complete Site Survey →</button>' + '</div>';
    return;
  }
  var statusMap = {
    current: ['#A3E851', '#05042E', 'Current'],
    due_soon: ['#FAEEDA', '#633806', 'Due Soon'],
    expired: ['#fee2e2', '#991b1b', 'Expired'],
    no_survey: ['#E0DFE1', '#05042E', 'No Survey']
  };
  var st = statusMap[s.survey_status] || statusMap.no_survey;
  var flags = [];
  if (s.vehicle_access) flags.push('Vehicle access');
  if (s.parking_loading_bay) flags.push('Parking / loading bay');
  if (s.access_restrictions) flags.push('Access restrictions');
  if (s.time_restrictions) flags.push('Time restrictions');
  if (s.lift_restrictions) flags.push('Lift available');
  if (s.narrow_corridors) flags.push('Narrow corridors');
  if (s.security_procedures) flags.push('Security procedures');
  card.style.display = 'block';
  card.innerHTML = '<div class="card-header"><i class="ti ti-clipboard-check" style="font-size:13px"></i><span class="card-title">Site Survey</span>' + '<span style="font-size:10px;font-weight:600;padding:2px 8px;border-radius:20px;background:' + st[0] + ';color:' + st[1] + '">' + st[2] + '</span></div>' + '<div class="card-body">' + '<div class="survey-meta">' + '<div class="survey-meta-item"><div class="survey-meta-label">Completed by</div><div class="survey-meta-value">' + (s.completed_by || '—') + '</div></div>' + '<div class="survey-meta-item"><div class="survey-meta-label">Completed</div><div class="survey-meta-value">' + fmt(s.completed_at) + '</div></div>' + '<div class="survey-meta-item"><div class="survey-meta-label">Review due</div><div class="survey-meta-value ' + (expiryClass(s.review_due) || '') + '">' + fmt(s.review_due) + '</div></div>' + '</div>' + (flags.length ? '<div class="survey-flags">' + flags.map(function (f) {
    return '<span class="survey-flag">' + f + '</span>';
  }).join('') + '</div>' : '') + (s.driver_instructions ? '<div class="survey-instructions"><strong>Driver instructions:</strong> ' + escHtml(s.driver_instructions) + '</div>' : '') + (s.survey_status === 'expired' ? '<div class="survey-alert danger-alert" style="margin-bottom:8px"><i class="ti ti-alert-triangle" style="font-size:13px;margin-right:6px"></i>Survey expired — review required before collection</div>' + '<button onclick="window.goToSurvey()" style="font-size:12px;font-weight:600;padding:7px 14px;border-radius:6px;border:none;cursor:pointer;background:#05042E;color:#A3E851;font-family:Figtree,sans-serif;width:100%">Review Site Survey →</button>' : '') + (s.survey_status === 'due_soon' ? '<div class="survey-alert warn-alert"><i class="ti ti-clock" style="font-size:13px;margin-right:6px"></i>Survey due for review soon</div>' : '') + '</div>';
}
function updateItemsCount() {
  var total = items.reduce(function (s, it) {
    return s + (parseInt(it.qty) || 0);
  }, 0);
  var el = document.getElementById('items_count');
  if (el) el.textContent = total;
}
function renderItems() {
  var tbody = document.getElementById('items_body');
  if (!tbody) return;
  if (!items.length) {
    tbody.innerHTML = '<tr><td colspan="3" style="text-align:center;padding:1rem;font-size:12px;color:#888780">No items added yet</td></tr>';
    updateItemsCount();
    return;
  }
  tbody.innerHTML = items.map(function (it, i) {
    return '<tr>' + '<td><input class="item-input" value="' + escHtml(it.item) + '" placeholder="e.g. Laptops" onchange="window.updateItem(' + i + ',\'item\',this.value)"/></td>' + '<td class="item-qty"><input class="item-input" type="number" min="1" value="' + it.qty + '" style="text-align:center" onchange="window.updateItem(' + i + ',\'qty\',this.value)"/></td>' + '<td><button class="btn-remove" onclick="window.removeItem(' + i + ')"><i class="ti ti-x" style="font-size:12px"></i></button></td>' + '</tr>';
  }).join('');
  updateItemsCount();
}
window.onCustomerChange = function () {
  var sel = document.getElementById('f_customer');
  var id = sel ? sel.value : '';
  selectedSite = null;
  document.getElementById('selected_site_card').className = 'selected-site';
  document.getElementById('contact_card').style.display = 'none';
  var sc = document.getElementById('survey_card');
  if (sc) sc.style.display = 'none';
  var hint = document.getElementById('site_hint');
  var tbl = document.getElementById('site_table');
  if (!id) {
    if (hint) {
      hint.textContent = 'Select a customer to load their sites below';
      hint.style.display = 'block';
    }
    if (tbl) tbl.style.display = 'none';
    updateCompliance({});
    return;
  }
  appsmith.updateModel({
    col_customer_id: parseInt(id)
  });
  appsmith.triggerEvent('onCustomerSelected');
};
window.selectSite = function (i) {
  selectedSite = sites[i];
  if (!selectedSite) return;
  document.querySelectorAll('.site-table tbody tr').forEach(function (r) {
    r.className = '';
  });
  var row = document.getElementById('site_row_' + i);
  if (row) row.className = 'selected';
  var addr = [selectedSite.address1, selectedSite.address2, selectedSite.city, selectedSite.postcode].filter(Boolean).join(', ');
  document.getElementById('sel_addr').textContent = addr;
  document.getElementById('sel_contact').textContent = selectedSite.site_contact || '';
  document.getElementById('selected_site_card').className = 'selected-site show';
  document.getElementById('contact_card').style.display = 'block';
  var initials = (selectedSite.site_contact || '?').split(' ').map(function (w) {
    return w[0];
  }).join('').toUpperCase().substr(0, 2);
  document.getElementById('contact_avatar').textContent = initials;
  document.getElementById('contact_name').textContent = selectedSite.site_contact || '—';
  document.getElementById('contact_phone').textContent = selectedSite.contact_number || '—';
  document.getElementById('contact_email').textContent = selectedSite.contact_email || '—';
  appsmith.updateModel({
    col_site_id: selectedSite.site_id
  });
  appsmith.triggerEvent('onSiteSelected');
};
window.goToSurvey = function () {
  appsmith.triggerEvent('onGoToSurvey');
};
window.addItem = function () {
  items.push({
    item: '',
    qty: 1
  });
  renderItems();
};
window.updateItem = function (i, field, val) {
  if (items[i]) items[i][field] = field === 'qty' ? parseInt(val) || 1 : val;
  updateItemsCount();
};
window.removeItem = function (i) {
  items.splice(i, 1);
  renderItems();
};
window.cancelCollection = function () {
  appsmith.triggerEvent('onCancel');
};
window.saveCollection = function () {
  if (!document.getElementById('f_customer').value) {
    alert('Please select a customer');
    return;
  }
  if (!selectedSite) {
    alert('Please select a collection site');
    return;
  }
  if (!document.getElementById('f_job_type').value) {
    alert('Please select a job type');
    return;
  }
  if (!document.getElementById('f_date').value) {
    alert('Please select a collection date');
    return;
  }
  appsmith.updateModel({
    col_customer_id: parseInt(document.getElementById('f_customer').value),
    col_site_id: selectedSite.site_id,
    col_job_type: document.getElementById('f_job_type').value,
    col_date: document.getElementById('f_date').value,
    col_instructions: document.getElementById('f_instructions').value,
    col_notes: document.getElementById('f_notes').value,
    col_dial: compliance.dial_ref || null,
    col_dial_expiry: compliance.dial_expiry || null,
    col_msa: compliance.msa_signed || null,
    col_site_contact: selectedSite.site_contact || null,
    col_contact_number: selectedSite.contact_number || null,
    col_contact_email: selectedSite.contact_email || null,
    col_address1: selectedSite.address1 || null,
    col_address2: selectedSite.address2 || null,
    col_city: selectedSite.city || null,
    col_postcode: selectedSite.postcode || null,
    col_expected_assets: JSON.stringify(items)
  });
  appsmith.triggerEvent('onSaveCollection');
};
function render(model) {
  customers = model.customers || [];
  sites = model.sites || [];
  compliance = model.compliance || {};
  survey = model.survey || {};
  populateCustomers(customers);
  if (sites.length) renderSites(sites);
  updateCompliance(compliance);
  if (model.survey !== undefined) renderSurvey(survey);
  if (!items.length) renderItems();
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (model) {
  customers = model.customers || customers;
  sites = model.sites || [];
  compliance = model.compliance || compliance;
  survey = model.survey || {};
  populateCustomers(customers);
  renderSites(sites);
  updateCompliance(compliance);
  if (model.survey !== undefined) renderSurvey(survey);
});

